// ═══ TRANSITION ═══
{id:"fc12",n:"Forecheck — 1-2-2",cat:"transition",d:"basic",desc:"Standard forecheck. C angles, wings close, D hold line.",strat:"Built on ANGLES not speed. C picks a side and forces them the other way where the wing waits. D: STAY at the blue line.",phases:[
{id:0,t:"Forecheck Structure",desc:"C is the '1' going in. Wings are the '2'. D hold the blue line.",pos:{LW:{x:25,y:72,role:"Second layer, left. If C pushes them right, shift right to close the middle.",u:"hold"},C:{x:50,y:82,role:"ANGLE — don't run straight. Pick a side and cut off that option.",u:"sprint",key:"Straight at them = they go around. Pick a side."},RW:{x:75,y:72,role:"Second layer, right. Mirror LW. Stay connected.",u:"hold"},LD:{x:30,y:60,role:"Blue line, left. Gap control. Don't get caught deep.",u:"hold"},RD:{x:70,y:60,role:"Blue line, right. Prevent stretch pass.",u:"hold"},G:GK},opp:o5({x:42,y:93,l:"D1"},{x:58,y:91,l:"D2"},{x:15,y:82,l:"F1"},{x:85,y:82,l:"F2"},{x:50,y:80,l:"C"}),ball:{x:42,y:93},lanes:[]},
{id:1,t:"C Angles Left — Close the Trap",desc:"C pushes carrier left. LW steps up. Everyone adjusts.",pos:{LW:{x:30,y:75,role:"C angled them left. Slide RIGHT to take away middle. Trap them on the boards.",u:"run"},C:{x:35,y:85,role:"Pushing them to the left corner. Stay on them.",u:"sprint"},RW:{x:60,y:72,role:"Slide to center. Cover the middle of the floor.",u:"run"},LD:{x:25,y:62,role:"Shift to ball side. Step up if ball comes up boards.",u:"drift"},RD:{x:65,y:60,role:"Stay right. Cross-floor pass is yours.",u:"hold"},G:GK},opp:o5({x:20,y:90,l:"D1"},{x:55,y:88,l:"D2"},{x:12,y:80,l:"F1"},{x:80,y:78,l:"F2"},{x:45,y:82,l:"C"}),ball:{x:20,y:90},lanes:[]}]},
{id:"fc21",n:"Forecheck — 2-1-2",cat:"transition",d:"advanced",desc:"Send TWO deep. High risk, high reward. Force turnovers.",strat:"LW and C go HARD as the '2'. They trap the D between them. RW pivots in the middle. D play tighter gap. WARNING: if both forwards get beat, RW is alone. Use selectively when you need a goal.",phases:[
{id:0,t:"Send Two — Trap the D",desc:"LW and C go in hard. RW pivots. D tight.",pos:{LW:{x:28,y:84,role:"First in. Cut off the boards pass. Trap the D-man.",u:"sprint"},C:{x:48,y:82,role:"Second in. Take the middle. Between you and LW, trap the carrier.",u:"sprint"},RW:{x:62,y:70,role:"The '1' pivot. If they escape LW and C, you're the next line. Also cover the middle pass.",u:"hold"},LD:{x:28,y:58,role:"Tight gap. Aggressively jump on anything coming up the boards.",u:"hold"},RD:{x:65,y:58,role:"SAFETY. If everyone else gets beat, you MUST be back.",u:"hold",key:"You are the insurance on the 2-1-2. Stay home."},G:GK},opp:o5({x:38,y:93,l:"D1"},{x:58,y:91,l:"D2"},{x:15,y:80,l:"F1"},{x:85,y:80,l:"F2"},{x:50,y:78,l:"C"}),ball:{x:38,y:93},lanes:[]},
{id:1,t:"Turnover Won — Counter Attack",desc:"The trap worked. We win the ball and go the other way.",pos:{LW:{x:22,y:82,role:"You won the battle. Ball to C or carry it yourself.",u:"run",ball:true},C:{x:40,y:76,role:"Support LW. Receive and push up through the middle.",u:"sprint"},RW:{x:70,y:68,role:"Push wide right. We're attacking now.",u:"sprint"},LD:{x:25,y:62,role:"Jump into the rush. Join the attack.",u:"run"},RD:{x:62,y:58,role:"Follow up as safety.",u:"drift"},G:GK},opp:o5({x:35,y:88,l:"D1"},{x:55,y:86,l:"D2"},{x:20,y:78,l:"F1"},{x:80,y:76,l:"F2"},{x:50,y:80,l:"C"}),ball:{x:22,y:82},lanes:[{f:"LW",t:"C",ty:"primary"}]}]},
{id:"qu",n:"Quick Up",cat:"transition",d:"basic",desc:"Skip the slow breakout — hit wings in stride for a counterattack.",strat:"The quick up is a MINDSET. D gets the ball and looks up FIRST — before settling, before shoulder-checking. If a wing has speed, hit them in stride. The pass has to be hard and flat. Wings: ALWAYS be moving when D gets the ball.",phases:[
{id:0,t:"D Gets Ball — Look Up FIRST",desc:"Wings already moving. Quick outlet opportunity.",pos:{LW:{x:8,y:48,role:"GO. Sprint up the boards. Be flying when LD looks up.",u:"sprint"},C:{x:50,y:34,role:"Sprint through center. Get to middle of NZ.",u:"sprint"},RW:{x:88,y:44,role:"Drive wide right. Create the 3-lane attack.",u:"sprint"},LD:{x:24,y:12,role:"Look up FIRST. Hit LW in stride. Hard, flat pass up the boards.",u:"hold",ball:true,key:"Quick up only works if you look up BEFORE settling the ball."},RD:{x:68,y:10,role:"Support. Ready to jump into rush as trailer.",u:"run"},G:GK},opp:o5({x:40,y:26,l:"F1"},{x:20,y:34,l:"F2"},{x:70,y:28,l:"F3"},{x:30,y:50,l:"D1"},{x:65,y:50,l:"D2"}),ball:{x:24,y:12},lanes:[{f:"LD",t:"LW",ty:"primary"},{f:"LD",t:"C",ty:"secondary"}]},
{id:1,t:"Stretch Pass — 3-Lane Rush",desc:"LD fires up to LW. Three-lane attack develops.",pos:{LW:{x:10,y:64,role:"Catch in stride. Carry in or pass to C driving the net.",u:"sprint",ball:true},C:{x:45,y:56,role:"Drive the net. If LW enters zone, you better be at the net.",u:"sprint"},RW:{x:82,y:58,role:"Wide right. Cross-floor option. If LW draws the D, you're free.",u:"sprint"},LD:{x:25,y:24,role:"Follow the play. Trail at a safe distance.",u:"run"},RD:{x:62,y:20,role:"4th man on the rush. Push up through center.",u:"run"},G:GK},opp:o5({x:35,y:48,l:"F1"},{x:55,y:45,l:"F2"},{x:68,y:50,l:"F3"},{x:30,y:62,l:"D1"},{x:65,y:62,l:"D2"}),ball:{x:10,y:64},lanes:[{f:"LW",t:"C",ty:"primary"},{f:"LW",t:"RW",ty:"secondary"}]}]},
{id:"bck",n:"Backchecking",cat:"transition",d:"basic",desc:"Sprint back with purpose. Every player has a specific man to pick up.",strat:"Backchecking is the #1 reason we give up goals. The rule is DEAD SIMPLE: get INSIDE your man — between the opponent and our net. C picks up their most dangerous forward (usually middle). LW covers their RW. RW covers their LW. D retreat together. The hardest part is NOT watching the ball. Pick your man, get inside, stay with them.",phases:[
{id:0,t:"Sprint Back — Find Your Man",desc:"They have the ball. Everyone has an assignment. Get inside.",pos:{LW:{x:25,y:48,role:"Your check = their RW. Get INSIDE — between them and our net. Don't just run parallel.",u:"sprint"},C:{x:50,y:52,role:"First backchecker. Pick up their most dangerous forward — usually the middle man.",u:"sprint"},RW:{x:75,y:48,role:"Your check = their LW. Inside position. Don't ball-watch.",u:"sprint"},LD:{x:30,y:38,role:"Retreating to blue line. Gap control — close on ball carrier without getting beaten.",u:"sprint"},RD:{x:70,y:38,role:"Mirror LD. Stay connected side by side. Don't let them split you.",u:"sprint"},G:GK},opp:o5({x:50,y:60,l:"C"},{x:28,y:56,l:"RW"},{x:72,y:56,l:"LW"},{x:35,y:50,l:"D1"},{x:65,y:50,l:"D2"}),ball:{x:50,y:60},lanes:[]},
{id:1,t:"Matched Up — Defending",desc:"Everyone back in shape. Tight gaps. Inside position.",pos:{LW:{x:22,y:34,role:"Inside your man. If they get the ball, you're in position to pressure.",u:"hold"},C:{x:50,y:28,role:"Locked on their center. Don't let them get a free shot in the slot.",u:"hold"},RW:{x:78,y:34,role:"Mirror LW. Inside your man. Disciplined.",u:"hold"},LD:{x:30,y:24,role:"In position. Take away time and space. Box out.",u:"hold"},RD:{x:65,y:24,role:"Mirror LD. Stay with your man.",u:"hold"},G:GK},opp:o5({x:50,y:38,l:"C"},{x:24,y:40,l:"RW"},{x:76,y:40,l:"LW"},{x:35,y:34,l:"D1"},{x:65,y:34,l:"D2"}),ball:{x:50,y:40},lanes:[]}]},
// ═══ SYSTEMS ═══
{id:"d21",n:"Defending 2-on-1",cat:"systems",d:"basic",desc:"D takes the pass. Goalie takes the shot. The golden rule.",strat:"GOLDEN RULE: D takes the PASS, goalie takes the SHOOTER. D runs backward between the two attackers but SHADES toward the pass receiver. Your stick is in the passing lane at ALL times. If you commit to the shooter, they pass and it's a tap-in. TAKE THE PASS. Goalie: challenge out and take away the angle. This is YOUR save to make.",phases:[
{id:0,t:"2-on-1 Developing — D Retreats",desc:"They have numbers. D retreats between both. Goalie sets.",pos:{LW:{x:30,y:46,role:"BACKCHECK. Sprint. Even arriving late helps.",u:"sprint"},C:{x:50,y:50,role:"BACKCHECK. Sprint to support D.",u:"sprint"},RW:{x:70,y:46,role:"BACKCHECK.",u:"sprint"},LD:{x:42,y:24,role:"Retreat between the two attackers. Shade toward the pass receiver. Stick in the passing lane at ALL TIMES.",u:"run",key:"D = PASS. Goalie = SHOT. If you commit to the shooter, they pass for a tap-in."},RD:{x:62,y:16,role:"If you're back, cover the late trailer. If not, sprint.",u:"sprint"},G:{x:50,y:9,role:"Square to the shooter. Challenge out to cut the angle. This is YOUR save.",u:"hold"}},opp:o5({x:38,y:34,l:"F1"},{x:58,y:32,l:"F2"},{x:50,y:52,l:"F3"},{x:35,y:58,l:"D1"},{x:65,y:58,l:"D2"}),ball:{x:38,y:34},lanes:[]},
{id:1,t:"Shooter Decides — D Holds Lane",desc:"The shooter is about to make a play. D stays disciplined.",pos:{LW:{x:30,y:36,role:"Almost back. Sprint to help clear the rebound.",u:"sprint"},C:{x:48,y:40,role:"Getting close. Pick up the trailer.",u:"sprint"},RW:{x:65,y:36,role:"Getting back.",u:"sprint"},LD:{x:42,y:18,role:"HOLD the passing lane. Don't lunge at the shooter — that's the goalie's job. If they shoot, help clear the rebound. If they pass, intercept.",u:"hold",key:"PATIENCE. The shooter wants you to bite. Stay in the lane. Let the goalie make the save."},RD:{x:58,y:14,role:"Cover net-front for rebounds.",u:"hold"},G:{x:50,y:9,role:"Take the shot. Be big. Rebound control.",u:"hold"}},opp:o5({x:38,y:24,l:"F1"},{x:58,y:22,l:"F2"},{x:50,y:42,l:"F3"},{x:35,y:56,l:"D1"},{x:65,y:56,l:"D2"}),ball:{x:38,y:24},lanes:[]}]},
{id:"d32",n:"Defending 3-on-2",cat:"systems",d:"intermediate",desc:"3-on-2 rush. Both D retreat side by side. Stay connected. Don't both commit to the ball.",strat:"Both D retreat side by side — NEVER split up. Strong-side D (ball side) tightens the gap on the shooter and forces a bad shot or pass. Weak-side D covers the back-door pass and far-side attacker. CRITICAL: don't BOTH commit to the ball carrier. If you both go, the pass across is a wide-open goal. Backchecker: pick up the middle man to take away the 3rd option.",phases:[
{id:0,t:"3-on-2 — Both D Retreat",desc:"They have 3 on our 2 D. Stay connected and retreat together.",pos:{LW:{x:30,y:40,role:"SPRINT back. Pick up the trailing attacker.",u:"sprint"},C:{x:50,y:46,role:"BACKCHECK to the middle. Cover the 3rd man. Your arrival changes everything.",u:"sprint"},RW:{x:70,y:40,role:"SPRINT back. Get inside your man.",u:"sprint"},LD:{x:35,y:22,role:"Strong-side D. Tighten gap on the ball carrier. Force a bad shot or pass.",u:"run",key:"Don't both go to the ball. You take the shooter, RD covers the pass."},RD:{x:58,y:20,role:"Weak-side D. Cover the far-side attacker and the back-door pass. Stay connected to LD.",u:"hold"},G:{x:50,y:9,role:"Be big. Take the first shot. Trust your D to cover the pass.",u:"hold"}},opp:o5({x:40,y:34,l:"F1"},{x:60,y:32,l:"F2"},{x:50,y:42,l:"F3"},{x:35,y:56,l:"D1"},{x:65,y:56,l:"D2"}),ball:{x:40,y:34},lanes:[]},
{id:1,t:"Contain — Make Them Earn It",desc:"D in position. Force a low-percentage play.",pos:{LW:{x:30,y:30,role:"Getting back. Cut off the late options.",u:"sprint"},C:{x:48,y:34,role:"You've arrived. Pick up the trailer. Now it's 3-on-3.",u:"run"},RW:{x:68,y:30,role:"Getting back. Cover the weak side.",u:"sprint"},LD:{x:36,y:16,role:"Gap is tight. You're forcing the shooter wide. Bad angle = low danger shot.",u:"hold",key:"PATIENCE. Make them make the first move. Don't lunge."},RD:{x:56,y:14,role:"Covering the pass option. Stick in the lane. Net-front awareness.",u:"hold"},G:{x:50,y:9,role:"Square. Let D funnel them to a bad angle. Control the rebound.",u:"hold"}},opp:o5({x:32,y:22,l:"F1"},{x:58,y:20,l:"F2"},{x:48,y:30,l:"F3"},{x:35,y:54,l:"D1"},{x:65,y:54,l:"D2"}),ball:{x:32,y:22},lanes:[]}]},
{id:"o21",n:"Offensive 2-on-1",cat:"systems",d:"basic",desc:"We have a 2-on-1! Drive wide, read the D, and finish it.",strat:"Ball carrier drives wide to pull the D toward you. Then read the D's stick — if it's in the passing lane, SHOOT. If it's not, pass to your teammate driving the net. Simple is deadly on a 2-on-1.",phases:[
{id:0,t:"2-on-1 Rush — Drive Wide",desc:"Pull the D. Read their stick for your decision.",pos:{LW:{x:30,y:60,role:"Ball carrier. Drive WIDE to pull the D toward you. Read their stick.",u:"sprint",ball:true,key:"D's stick in the passing lane = SHOOT. Not in the lane = PASS."},C:{x:55,y:57,role:"Passing option. Drive the net HARD. Stick on the floor. Call for it.",u:"sprint",comm:"GIVE!"},RW:{x:75,y:46,role:"Trail for rebound. Don't crowd the play.",u:"run"},LD:{x:30,y:42,role:"Follow for safety.",u:"run"},RD:{x:60,y:38,role:"Support.",u:"drift"},G:GK},opp:o5g({x:42,y:65,l:"D1"},{x:55,y:72,l:"F1"},{x:70,y:68,l:"F2"},{x:40,y:78,l:"D2"},{x:65,y:78,l:"F3"},{x:50,y:96,l:"G"}),ball:{x:30,y:60},lanes:[{f:"LW",t:"C",ty:"primary"}]},
{id:1,t:"Finish It — Shoot or Pass",desc:"D commits. Exploit the opening. Score.",pos:{LW:{x:25,y:72,role:"D stepped toward you. Pass to C for the easy finish OR shoot far-side.",u:"sprint",ball:true},C:{x:55,y:72,role:"At the net. Stick down. If LW passes, one-touch it in. No extra touches.",u:"sprint"},RW:{x:72,y:60,role:"Crash for any rebound. Be ready for garbage.",u:"run"},LD:{x:28,y:56,role:"Follow up. Get to the net for rebounds.",u:"run"},RD:{x:58,y:50,role:"Hold for safety in case it comes back.",u:"drift"},G:GK},opp:o5g({x:34,y:70,l:"D1"},{x:52,y:76,l:"F1"},{x:68,y:72,l:"F2"},{x:40,y:80,l:"D2"},{x:65,y:80,l:"F3"},{x:50,y:96,l:"G"}),ball:{x:25,y:72},lanes:[{f:"LW",t:"C",ty:"primary"}]}]},
{id:"o32",n:"Offensive 3-on-2",cat:"systems",d:"intermediate",desc:"3-on-2 rush! Use the extra man. Middle drives, wings stay wide.",strat:"Middle man is the KEY. Drive up the middle to freeze both D — they can't commit to either wing. If D1 steps up to you, pass to the open wing. If both D back up, drive it yourself and shoot. Wings: STAY WIDE. The width is what makes 3-on-2 deadly.",phases:[
{id:0,t:"3-on-2 — Three Wide Lanes",desc:"Middle man drives. Wings stay in their lanes WIDE.",pos:{LW:{x:15,y:62,role:"Left lane. STAY WIDE. Give the middle man space to operate.",u:"sprint"},C:{x:45,y:60,role:"DRIVE THE MIDDLE. Make both D respect you. They can't commit to both wings if you're a threat.",u:"sprint",ball:true,key:"D steps up to you = pass to the open wing. Both D back = drive and shoot."},RW:{x:80,y:60,role:"Right lane. STAY WIDE. One-timer ready if ball comes across.",u:"sprint"},LD:{x:30,y:46,role:"Trail the play. Point support.",u:"run"},RD:{x:65,y:44,role:"Safety. Cover if it turns over.",u:"hold"},G:GK},opp:o5g({x:35,y:68,l:"D1"},{x:62,y:68,l:"D2"},{x:50,y:76,l:"F1"},{x:25,y:74,l:"F2"},{x:75,y:74,l:"F3"},{x:50,y:96,l:"G"}),ball:{x:45,y:60},lanes:[{f:"C",t:"LW",ty:"primary"},{f:"C",t:"RW",ty:"primary"}]},
{id:1,t:"D Commits — Hit the Open Man",desc:"Their D steps up. Pass to the open wing and crash.",pos:{LW:{x:15,y:74,role:"D1 stepped to C. You're OPEN. Stick on the floor. Ready for the pass.",u:"sprint"},C:{x:42,y:70,role:"D stepped up. Pass to LW and drive to the net for the rebound.",u:"sprint",ball:true},RW:{x:78,y:72,role:"Drive to the far post. If the play comes across, finish it.",u:"sprint"},LD:{x:28,y:58,role:"Join the rush. Get to the slot for the rebound.",u:"sprint"},RD:{x:62,y:54,role:"Hold for safety.",u:"hold"},G:GK},opp:o5g({x:38,y:70,l:"D1"},{x:60,y:70,l:"D2"},{x:48,y:78,l:"F1"},{x:25,y:78,l:"F2"},{x:72,y:78,l:"F3"},{x:50,y:96,l:"G"}),ball:{x:42,y:70},lanes:[{f:"C",t:"LW",ty:"primary"}]}]},
{id:"pomr",n:"Preventing Odd-Man Rushes",cat:"systems",d:"basic",desc:"THE #1 PROBLEM. How to stop giving up 3-on-2 and 4-on-2 rushes every game.",strat:"WHY we give up odd-man rushes: (1) All 3 forwards go deep — nobody gets back. (2) Both D pinch — the middle is wide open. (3) Bad line changes — we change when the ball is in the neutral zone. THE FIX is three rules carved in stone: RULE 1: Only 2 forwards go deep. The 3rd forward (usually the weak-side wing) stays HIGH at the top of their zone as insurance. RULE 2: Only 1 D pinches at a time. The other D ALWAYS stays home. If you're RD and LD pinches, you DO NOT leave your position. RULE 3: When you hear 'CHANGE!' in the offensive zone, the high forward changes FIRST (they're closest to the bench), then the other forward, then D together. NEVER change in the neutral zone with the ball coming our way. These three rules eliminate 80% of odd-man rushes OVERNIGHT. The discipline is hard — you WANT to jump into the play. But one player staying disciplined prevents a goal against.",phases:[
{id:0,t:"Rule 1: High Forward",desc:"2 forwards go deep. 3rd stays HIGH at top of zone as insurance.",pos:{LW:{x:15,y:85,role:"Go deep. Forecheck hard. You and C are the two going in.",u:"sprint"},C:{x:38,y:80,role:"Second forechecker. Support LW. You two create pressure.",u:"run"},RW:{x:68,y:65,role:"⚠️ HIGH FORWARD. You are the INSURANCE POLICY. Stay at the top of their zone. Do NOT go deep. If we lose the ball, you're the first one back. Your discipline prevents the 3-on-2.",u:"hold",key:"This is the HARDEST job because you WANT to jump in. RESIST. Every time you stay high, you prevent a rush."},LD:{x:25,y:65,role:"Left point. You CAN pinch because RD is staying home.",u:"hold"},RD:{x:62,y:58,role:"⚠️ STAY HOME D. You are the last line of defense. If LD pinches and it turns over, you prevent the odd-man rush.",u:"hold"},G:GK},opp:o5({x:30,y:93,l:"D1"},{x:60,y:91,l:"D2"},{x:50,y:78,l:"F1"},{x:20,y:80,l:"F2"},{x:75,y:80,l:"F3"}),ball:{x:25,y:88},lanes:[]},
{id:1,t:"Rule 2: One D Pinches Only",desc:"LD pinches on boards. RD stays HOME. Never both.",pos:{LW:{x:18,y:82,role:"Support the pinch. If LD gets the ball, you're the outlet.",u:"run"},C:{x:35,y:78,role:"Support LD's pinch. Be the middle option.",u:"run"},RW:{x:68,y:65,role:"STILL HIGH. Insurance hasn't changed.",u:"hold"},LD:{x:18,y:72,role:"PINCHING. You're stepping up to the boards to keep the ball in their zone.",u:"sprint",key:"You can pinch because RD is covering behind you. If this fails, RD has it."},RD:{x:62,y:58,role:"⚠️ YOU SEE LD PINCHING. That means you STAY. Do NOT follow. You are the backstop.",u:"hold",key:"If both D go and it turns over = instant 3-on-1. STAY."},G:GK},opp:o5({x:22,y:80,l:"D1"},{x:58,y:88,l:"D2"},{x:45,y:75,l:"F1"},{x:18,y:78,l:"F2"},{x:75,y:78,l:"F3"}),ball:{x:18,y:78},lanes:[]},
{id:2,t:"Turnover — System Works",desc:"They get the ball. But RW and RD are already back. No odd-man rush.",pos:{LW:{x:28,y:70,role:"BACKCHECK. Sprint back on left side.",u:"sprint"},C:{x:50,y:68,role:"BACKCHECK. Get to the middle. Pick up their center.",u:"sprint"},RW:{x:62,y:56,role:"✅ You're ALREADY back because you stayed high. You're the first backchecker. Pick up their most dangerous man.",u:"sprint"},LD:{x:32,y:60,role:"Got caught on the pinch. Sprint back. You're behind but help is already there.",u:"sprint"},RD:{x:58,y:50,role:"✅ You're ALREADY in position because you stayed home. Gap control. Take away the middle.",u:"hold"},G:GK},opp:o5({x:50,y:72,l:"F1"},{x:28,y:68,l:"F2"},{x:72,y:68,l:"F3"},{x:40,y:80,l:"D1"},{x:65,y:78,l:"D2"}),ball:{x:50,y:72},lanes:[]},
{id:3,t:"⚠️ What Happens WITHOUT Insurance",desc:"BAD: All 3 forwards deep + both D pinch = 3-on-1 against us.",pos:{LW:{x:15,y:85,role:"❌ ALL 3 FORWARDS DEEP. Nobody stayed high. Now you're all caught behind the play.",u:"sprint"},C:{x:30,y:82,role:"❌ You went deep too. Now you AND LW AND RW are all behind the ball.",u:"sprint"},RW:{x:75,y:80,role:"❌ You SHOULD have stayed high but you went deep. Now nobody is back.",u:"sprint"},LD:{x:20,y:72,role:"❌ You pinched AND RD pinched. Both of you are caught.",u:"sprint"},RD:{x:55,y:70,role:"❌ You BOTH pinched. Nobody stayed home. This is a 3-on-1.",u:"sprint",key:"THIS IS HOW 3-ON-2s HAPPEN. Both D out of position + all forwards deep = disaster."},G:GK},opp:o5({x:50,y:68,l:"F1"},{x:28,y:65,l:"F2"},{x:72,y:65,l:"F3"},{x:40,y:78,l:"D1"},{x:65,y:78,l:"D2"}),ball:{x:50,y:68},lanes:[]}]},
{id:"lcs",n:"Line Change Strategy",cat:"systems",d:"basic",desc:"When, how, and where to change — including when D has ball in our zone.",strat:"RULES CARVED IN STONE: (1) WHEN: Only change with possession in their zone, after whistles, OR when our D has the ball behind our net with time. NEVER when ball is in NZ coming toward us. (2) HOW: One at a time. Guy coming ON doesn't go until guy coming OFF is at the bench. (3) WHO FIRST: High forward (weak-side) changes first — they're closest to bench. Then the other forward. Then D change TOGETHER. (4) BENCH TIMING: If you've been on for 45-60 seconds, start thinking about a change. At 60-90 seconds you MUST change. Over 90 seconds your legs are dead and you become a liability. (5) CARDINAL SIN: Changing when the ball is in our zone under PRESSURE or coming our way. A tired player is ALWAYS better than being short-handed. (6) D-ZONE CHANGE: When our D retrieves the ball behind our net and there's NO pressure, D can HOLD the ball and let the forwards change. D calls 'CHANGE!' — the goalie can help communicate. Forwards sprint to bench one at a time. Fresh forwards come on and get to their breakout positions. THEN D starts the breakout with fresh legs in front of them. This is one of the smartest plays in hockey.",phases:[
{id:0,t:"Safe Change — O-Zone Possession",desc:"We have ball deep in their zone. Weak-side forward changes first.",pos:{LW:{x:15,y:85,role:"You have the ball deep. HOLD IT. Give teammates time to change. Call 'CHANGE!'",u:"hold",ball:true,comm:"CHANGE!"},C:{x:38,y:80,role:"Wait until RW's replacement is on. Then sprint to bench. Change SECOND.",u:"hold"},RW:{x:68,y:68,role:"Weak-side = change FIRST. You're farthest from the ball and closest to the bench. Sprint off, replacement gets on immediately.",u:"sprint",key:"Weak side = safest and first to change. Your replacement should be standing at the bench door ready."},LD:{x:25,y:65,role:"Hold the point. Do NOT change until both new forwards are on the floor.",u:"hold"},RD:{x:60,y:62,role:"Hold. When both fresh forwards are on, you and LD change TOGETHER as a pair.",u:"hold"},G:GK},opp:o5({x:30,y:91,l:"D1"},{x:58,y:89,l:"D2"},{x:45,y:80,l:"F1"},{x:24,y:78,l:"F2"},{x:70,y:76,l:"F3"}),ball:{x:15,y:85},lanes:[]},
{id:1,t:"D-Zone Change — D Has Ball Behind Net",desc:"D retrieves with no pressure. HOLD the ball and let forwards change.",pos:{LW:{x:14,y:34,role:"D has the ball with time. Sprint to the bench NOW. Your replacement comes on and gets to the left boards for the breakout.",u:"sprint",key:"Don't wait — go to the bench the moment D has it with time. Fresh legs = better breakout."},C:{x:50,y:28,role:"Wait for LW's replacement to step on. Then go to bench. Change SECOND.",u:"run"},RW:{x:85,y:34,role:"Wait for BOTH LW and C replacements. Then change THIRD. Or stay if your legs are fresh.",u:"hold"},LD:{x:35,y:4,role:"You have the ball behind the net with TIME. HOLD IT. Let the forwards change. Don't rush the breakout with tired forwards.",u:"hold",ball:true,comm:"CHANGE!",key:"This is a smart play — holding for 5 seconds lets 3 tired forwards become 3 fresh ones."},RD:{x:60,y:4,role:"Support LD. If pressure comes, be the outlet. D do NOT change here — you start the breakout after fresh forwards are set.",u:"hold"},G:{x:50,y:8,role:"Help communicate. Tell D how much time they have. Call out when fresh forwards are in position.",u:"hold",comm:"TAKE YOUR TIME!"}},opp:o5({x:42,y:20,l:"F1"},{x:18,y:30,l:"F2"},{x:72,y:28,l:"F3"},{x:30,y:48,l:"D1"},{x:65,y:48,l:"D2"}),ball:{x:35,y:4},lanes:[]},
{id:2,t:"Fresh Legs — Now Break Out",desc:"New forwards are on and in position. D starts the breakout with fresh teammates.",pos:{LW:{x:10,y:38,role:"✅ FRESH. You just stepped on. Get to left boards immediately. Call 'BOARDS!' so D knows you're ready.",u:"sprint",comm:"BOARDS!"},C:{x:48,y:32,role:"✅ FRESH. Get to the middle. Give D an outlet option.",u:"run"},RW:{x:86,y:38,role:"✅ FRESH. Wide right. Ready to fly through the neutral zone.",u:"run"},LD:{x:22,y:12,role:"Fresh forwards are set. NOW start the breakout. You have three players with full energy — this breakout will be fast.",u:"run",ball:true,key:"The beauty of the D-zone change: tired forwards became fresh ones. Your breakout has WAY more speed now."},RD:{x:58,y:10,role:"Support the breakout. You and LD haven't changed yet — save energy for the next D-zone change opportunity.",u:"run"},G:{x:50,y:8,role:"Great communication. The change worked. Now watch the breakout.",u:"hold"}},opp:o5({x:35,y:20,l:"F1"},{x:15,y:32,l:"F2"},{x:70,y:30,l:"F3"},{x:30,y:50,l:"D1"},{x:65,y:50,l:"D2"}),ball:{x:22,y:12},lanes:[{f:"LD",t:"LW",ty:"primary"},{f:"LD",t:"C",ty:"secondary"}]},
{id:3,t:"⚠️ NEVER Change Here",desc:"Ball coming toward our zone. Nobody changes. Defend.",pos:{LW:{x:25,y:44,role:"DO NOT CHANGE. Ball is coming our way. Get back and defend.",u:"sprint"},C:{x:50,y:46,role:"DO NOT CHANGE. Backcheck. Find your man.",u:"sprint"},RW:{x:75,y:44,role:"DO NOT CHANGE. Even if you're exhausted. A tired player is ALWAYS better than no player.",u:"sprint",key:"Changing when ball comes our way = playing 5-on-4 in our zone. That's how we give up goals."},LD:{x:30,y:36,role:"GET BACK. No changes. Retreat to your defensive position.",u:"sprint"},RD:{x:68,y:36,role:"GET BACK. You and LD must be the first ones back.",u:"sprint"},G:{x:50,y:8,role:"If you see someone trying to change at the wrong time, YELL at them.",u:"hold",comm:"NO CHANGE!"}},opp:o5({x:50,y:58,l:"F1"},{x:28,y:54,l:"F2"},{x:72,y:54,l:"F3"},{x:35,y:50,l:"D1"},{x:65,y:50,l:"D2"}),ball:{x:50,y:58},lanes:[]}]},
{id:"dzr",n:"D-Zone Recovery",cat:"systems",d:"intermediate",desc:"Caught up ice. Rebuild shape.",strat:"D to circles FAST. Zone first, then pick up.",phases:[
{id:0,t:"Sprint Back",desc:"Everyone retreats.",pos:{LW:{x:25,y:44,role:"Left hash.",u:"sprint"},C:{x:50,y:46,role:"Slot.",u:"sprint"},RW:{x:75,y:44,role:"Right hash.",u:"sprint"},LD:{x:30,y:34,role:"Left circle.",u:"sprint"},RD:{x:65,y:34,role:"Match LD.",u:"sprint"},G:GK},opp:o5({x:50,y:54,l:"F1"},{x:28,y:50,l:"F2"},{x:72,y:50,l:"F3"},{x:35,y:48,l:"D1"},{x:65,y:48,l:"D2"}),ball:{x:50,y:54},lanes:[]},
{id:1,t:"Shape Recovered",desc:"Positions set.",pos:{LW:{x:20,y:28,role:"Hash. Point man.",u:"hold"},C:{x:50,y:22,role:"Slot.",u:"hold"},RW:{x:75,y:28,role:"Hash.",u:"hold"},LD:{x:30,y:18,role:"Circle.",u:"hold"},RD:{x:65,y:18,role:"Connected with LD.",u:"hold"},G:GK},opp:o5({x:50,y:38,l:"F1"},{x:22,y:35,l:"F2"},{x:78,y:35,l:"F3"},{x:32,y:42,l:"D1"},{x:68,y:42,l:"D2"}),ball:{x:50,y:38},lanes:[]}]}
